SELECT id, position, plugin_type, content
FROM page_elements
WHERE placeholder_id = 1;

SELECT page_name
FROM page_structure
WHERE created_by = 1;

SELECT 
    (SELECT COUNT(*) FROM page_elements) AS total_page_elements,
    (SELECT COUNT(*) FROM page_structure) AS total_page_structures;

SELECT users.username, users.email
FROM users
WHERE users.user_id IN (
  SELECT page_structure_history.changed_by
  FROM page_structure_history
) AND users.user_id NOT IN (
  SELECT page_element_history.changed_by
  FROM page_element_history
);

SELECT u.username
FROM users u
WHERE u.user_id IN (
    SELECT ps.created_by
    FROM page_structure ps
)
AND u.user_id NOT IN (
    SELECT pe.created_by
    FROM page_elements pe
);

SELECT id, numchild,
       RANK() OVER (ORDER BY numchild DESC) AS rank
FROM page_elements;

SELECT 
    (SELECT MIN(page_id) FROM page_structure) AS smallest_page_id,
    (SELECT MIN(placeholder_id) FROM placeholders) AS smallest_placeholder_id;

SELECT COUNT(ps.page_id) / COUNT(DISTINCT u.user_id) AS average_pages_per_user
FROM users u
JOIN page_structure ps ON u.user_id = ps.created_by;

SELECT username 
FROM users
WHERE user_id NOT IN (SELECT created_by FROM page_elements);

SELECT COUNT(*)
FROM page_element_history
WHERE page_element_id = 1 AND action = 'update';
